import{_ as e,o as r,c as a,ak as s}from"./chunks/framework.DwHlt8HN.js";const g=JSON.parse('{"title":"Features","description":"XW37-BLE module features and capabilities","frontmatter":{"title":"Features","description":"XW37-BLE module features and capabilities"},"headers":[],"relativePath":"docs/overview/features.md","filePath":"docs/overview/features.md"}'),o={name:"docs/overview/features.md"};function l(i,t,n,d,c,u){return r(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="product-features" tabindex="-1">Product Features <a class="header-anchor" href="#product-features" aria-label="Permalink to “Product Features”">​</a></h1><h2 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to “Core Features”">​</a></h2><ul><li><strong>Ultra-small size</strong> low-power Bluetooth 5.2 module</li><li><strong>Built-in 12-bit high-precision ADC</strong></li><li><strong>Deep sleep current:</strong> 0.8µA</li></ul><h2 id="supported-interfaces" tabindex="-1">Supported Interfaces <a class="header-anchor" href="#supported-interfaces" aria-label="Permalink to “Supported Interfaces”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Interface</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>UART</strong></td><td style="text-align:left;">Serial communication</td></tr><tr><td style="text-align:left;"><strong>GPIO</strong></td><td style="text-align:left;">General Purpose I/O</td></tr><tr><td style="text-align:left;"><strong>I2C</strong></td><td style="text-align:left;">Inter-Integrated Circuit</td></tr><tr><td style="text-align:left;"><strong>PWM</strong></td><td style="text-align:left;">Pulse Width Modulation</td></tr><tr><td style="text-align:left;"><strong>ADC</strong></td><td style="text-align:left;">Analog-to-Digital Converter</td></tr><tr><td style="text-align:left;"><strong>SPI</strong></td><td style="text-align:left;">Serial Peripheral Interface</td></tr><tr><td style="text-align:left;"><strong>JTAG</strong></td><td style="text-align:left;">Debugging interface</td></tr></tbody></table><h2 id="communication-features" tabindex="-1">Communication Features <a class="header-anchor" href="#communication-features" aria-label="Permalink to “Communication Features”">​</a></h2><ul><li>Supports command-based switching between <strong>AT mode</strong> and <strong>Transparent transmission mode</strong></li><li>Supports AT command configuration</li><li><strong>Communication distance:</strong> Up to 40m in open areas at 0dBm transmit power</li><li><strong>Max packet size:</strong> 20 bytes per frame</li></ul><h2 id="power-features" tabindex="-1">Power Features <a class="header-anchor" href="#power-features" aria-label="Permalink to “Power Features”">​</a></h2><ul><li><strong>Power supply:</strong> 1.7V to 3.3V (3.0V recommended)</li><li>Pins can enable the serial port to switch between working and sleep states</li></ul><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>The module achieves ultra-low power consumption of just 0.8µA in deep sleep mode, making it ideal for battery-powered IoT applications.</p></div>',10)])])}const f=e(o,[["render",l]]);export{g as __pageData,f as default};
